namespace sv_a522fa0102124fa9ad022be59310cefa.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Reusable message input with textarea and send/reply button *@

<div class="message-input">
    <textarea class="message-input__textarea"
              @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="message-input__button"
            @onclick="HandleSend"
            disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var message = Text.Trim();
        Text = "";
        await OnSend.InvokeAsync(message);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await HandleSend();
        }
    }
}

@using sv_a522fa0102124fa9ad022be59310cefa.Services

<div class="message-bubble" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-bubble__header">
        <span class="message-bubble__author">@Message.Author</span>
        <span class="message-bubble__time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-bubble__content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-bubble__reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="message-bubble__thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions && ShowActions)
    {
        <div class="message-bubble__actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">💬</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😊</button>
        </div>

        @if (showEmojiPicker)
        {
            <div class="message-bubble__emoji-picker">
                @foreach (var emoji in CommonEmojis)
                {
                    <button class="emoji-pick" @onclick="() => PickEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public bool ShowActions { get; set; } = true;
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@using sv_a522fa0102124fa9ad022be59310cefa.Services

<button class="channel-item @(IsActive ? "channel-item--active" : "")"
        @onclick="() => OnSelect.InvokeAsync(Channel.Id)">
    <div class="channel-item__header">
        <span class="channel-item__name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="channel-item__badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-item__desc">@TruncateDescription(Channel.Description)</div>
    }
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelect { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..37] + "…" : desc;
}

