@page "/chat"
@using sv_a522fa0102124fa9ad022be59310cefa.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <MessageArea class="@MessageAreaCssClass"
                 Channel="activeChannel"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 HasMoreMessages="hasMoreMessages"
                 IsLoadingMore="isLoadingMore"
                 OnLoadMore="LoadMoreMessages"
                 OnOpenThread="OpenThread"
                 OnReact="AddReaction"
                 OnSendMessage="SendMessage" />

    @if (threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private int activeChannelId;
    private Channel? activeChannel;
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private bool hasMoreMessages = true;
    private bool isLoadingMore;

    // Thread state
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private string MessageAreaCssClass => threadRootMessage is not null
        ? "chat-layout__main chat-layout__main--with-thread"
        : "chat-layout__main chat-layout__main--full";

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        hasMoreMessages = true;
        threadRootMessage = null;
        threadReplies = [];

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;

        threadSummaries = BuildThreadSummaries(messages);

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the channel's unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages || activeChannel is null) return;

        isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        hasMoreMessages = older.Count == PageSize;
        messages.InsertRange(0, older);
        threadSummaries = BuildThreadSummaries(messages);
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;
        var msg = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        var thread = await ChatService.GetThreadAsync(rootMessageId);
        // First message in thread is the root; replies are the rest
        threadReplies = thread.Where(m => m.Id != rootMessageId).ToList();
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary in main view
        threadSummaries = BuildThreadSummaries(messages, threadRootMessage.Id, threadReplies.Count);
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Refresh the message list to show updated reactions
        if (activeChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(activeChannelId, 0, messages.Count);
            messages = refreshed;
        }
    }

    private static List<ThreadSummary> BuildThreadSummaries(List<Message> msgs, int? updatedRootId = null, int? updatedCount = null)
    {
        var replies = msgs.Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();

        if (updatedRootId.HasValue && updatedCount.HasValue)
        {
            var existing = replies.FindIndex(t => t.RootMessageId == updatedRootId.Value);
            var summary = new ThreadSummary(updatedRootId.Value, updatedCount.Value, DateTime.UtcNow);
            if (existing >= 0)
                replies[existing] = summary;
            else
                replies.Add(summary);
        }

        return replies;
    }
}

