toolArgs.file_text:
/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

/* ===== Channel Sidebar ===== */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2b2d42;
    color: #edf2f4;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
    border-right: 1px solid #1a1b2e;
}

.channel-sidebar__title {
    font-size: 1rem;
    font-weight: 700;
    padding: 1rem;
    margin: 0;
    border-bottom: 1px solid #3d3f5c;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8d99ae;
}

.channel-sidebar__list {
    display: flex;
    flex-direction: column;
    padding: 0.25rem 0;
}

/* ===== Channel List Item ===== */
.channel-item {
    display: block;
    width: 100%;
    background: none;
    border: none;
    color: #c0c7d4;
    text-align: left;
    padding: 0.6rem 1rem;
    cursor: pointer;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.06);
}

.channel-item--active {
    background: rgba(255, 255, 255, 0.12);
    color: #fff;
    border-left: 3px solid #ef233c;
}

.channel-item__header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-item__name {
    font-weight: 600;
    font-size: 0.9rem;
}

.channel-item__badge {
    background: #ef233c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 0.1rem 0.45rem;
    border-radius: 10px;
    min-width: 1.2rem;
    text-align: center;
}

.channel-item__desc {
    font-size: 0.75rem;
    color: #8d99ae;
    margin-top: 0.15rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ===== Message Area ===== */
.message-area {
    display: flex;
    flex-direction: column;
    background: #f8f9fa;
    overflow: hidden;
}

.chat-layout__main--full {
    flex: 1;
}

.chat-layout__main--with-thread {
    width: 55%;
}

.message-area__header {
    padding: 0.75rem 1.25rem;
    border-bottom: 1px solid #dee2e6;
    background: #fff;
}

.message-area__channel-name {
    font-size: 1.1rem;
    font-weight: 700;
    margin: 0;
    color: #2b2d42;
}

.message-area__channel-desc {
    font-size: 0.8rem;
    color: #6c757d;
    margin: 0.15rem 0 0;
}

.message-area__messages {
    flex: 1;
    overflow-y: auto;
    padding: 1rem 1.25rem;
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.message-area__load-more {
    align-self: center;
    padding: 0.35rem 1rem;
    border: 1px solid #dee2e6;
    border-radius: 1rem;
    background: #fff;
    color: #495057;
    font-size: 0.8rem;
    cursor: pointer;
    margin-bottom: 0.75rem;
    transition: background 0.15s;
}

.message-area__load-more:hover:not(:disabled) {
    background: #e9ecef;
}

.message-area__load-more:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.message-area__empty {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #8d99ae;
    font-size: 1.1rem;
}

/* ===== Message List ===== */
.message-list {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.message-list__loading {
    text-align: center;
    color: #8d99ae;
    font-size: 0.85rem;
    padding: 0.5rem;
}

/* ===== Message Bubble ===== */
.message-bubble {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    transition: background 0.15s;
}

.message-bubble:hover {
    background: rgba(0, 0, 0, 0.03);
}

.message-bubble__header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
}

.message-bubble__author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #2b2d42;
}

.message-bubble__time {
    font-size: 0.72rem;
    color: #8d99ae;
}

.message-bubble__content {
    font-size: 0.9rem;
    color: #333;
    margin-top: 0.15rem;
    line-height: 1.45;
    word-wrap: break-word;
}

.message-bubble__reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.3rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    padding: 0.1rem 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 1rem;
    background: #fff;
    font-size: 0.78rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s;
}

.reaction-badge:hover {
    background: #e8f4fd;
    border-color: #90caf9;
}

.message-bubble__thread-link {
    display: inline-block;
    margin-top: 0.25rem;
    background: none;
    border: none;
    color: #1976d2;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 0.1rem 0;
}

.message-bubble__thread-link:hover {
    text-decoration: underline;
}

