+.message-input {
+    display: flex;
+    gap: 0.5rem;
+    padding: 0.75rem 1.25rem;
+    border-top: 1px solid #dee2e6;
+    background: #fff;
+    align-items: flex-end;
+}
+
+.message-input__textarea {
+    flex: 1;
+    border: 1px solid #ced4da;
+    border-radius: 8px;
+    padding: 0.5rem 0.75rem;
+    font-size: 0.9rem;
+    font-family: inherit;
+    resize: none;
+    outline: none;
+    transition: border-color 0.15s;
+}
+
+.message-input__textarea:focus {
+    border-color: #1976d2;
+    box-shadow: 0 0 0 2px rgba(25, 118, 210, 0.15);
+}
+
+.message-input__button {
+    padding: 0.5rem 1.25rem;
+    background: #1976d2;
+    color: #fff;
+    border: none;
+    border-radius: 8px;
+    font-weight: 600;
+    font-size: 0.85rem;
+    cursor: pointer;
+    transition: background 0.15s;
+    white-space: nowrap;
+}
+
+.message-input__button:hover:not(:disabled) {
+    background: #1565c0;
+}
+
+.message-input__button:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* ===== Thread Panel ===== */
+.thread-panel {
+    width: 25%;
+    min-width: 260px;
+    background: #fff;
+    border-left: 1px solid #dee2e6;
+    display: flex;
+    flex-direction: column;
+    overflow: hidden;
+}
+
+.thread-panel__header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 0.75rem 1rem;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.thread-panel__header h3 {
+    margin: 0;
+    font-size: 1rem;
+    font-weight: 700;
+    color: #2b2d42;
+}
+
+.thread-panel__close {
+    background: none;
+    border: none;
+    font-size: 1.1rem;
+    color: #6c757d;
+    cursor: pointer;
+    padding: 0.2rem 0.4rem;
+    border-radius: 4px;
+    transition: background 0.15s;
+}
+
+.thread-panel__close:hover {
+    background: #e9ecef;
+    color: #333;
+}
+
+.thread-panel__root {
+    padding: 0.75rem 1rem;
+    border-bottom: 1px solid #eee;
+    background: #f8f9fa;
+}
+
+.thread-panel__replies {
+    flex: 1;
+    overflow-y: auto;
+    padding: 0.5rem 1rem;
+    display: flex;
+    flex-direction: column;
+    gap: 0.25rem;
+}
