namespace sv_a522fa0102124fa9ad022be59310cefa.Services;

/// <summary>
/// In-memory stub implementation of IChatService for development/testing.
/// Replace with a real implementation backed by a database or API.
/// </summary>
public class StubChatService : IChatService
{
    private readonly List<Channel> _channels =
    [
        new(1, "general", "General discussion for the team", 3),
        new(2, "engineering", "Engineering updates and code reviews", 0),
        new(3, "design", "Design feedback and assets", 1),
        new(4, "random", "Off-topic fun and memes", 5),
    ];

    private readonly List<Message> _messages;
    private int _nextId = 100;

    public StubChatService()
    {
        _messages =
        [
            new(1, 1, "Alice", "Hey team! Welcome to the new chat app 🎉", DateTime.UtcNow.AddHours(-3), null, [new("🎉", ["Bob", "Carol"])]),
            new(2, 1, "Bob", "Looks great! Love the new layout.", DateTime.UtcNow.AddHours(-2.5), null, [new("👍", ["Alice"])]),
            new(3, 1, "Carol", "Are we migrating all conversations here?", DateTime.UtcNow.AddHours(-2), null, []),
            new(4, 1, "Alice", "Yes, starting next week we'll be fully on this platform.", DateTime.UtcNow.AddHours(-1.5), 3, []),
            new(5, 1, "Dave", "Can we get dark mode? 😎", DateTime.UtcNow.AddMinutes(-45), null, [new("👀", ["Alice", "Bob"]), new("😂", ["Carol"])]),
            new(6, 1, "Bob", "Already on the roadmap!", DateTime.UtcNow.AddMinutes(-30), 5, []),
            new(7, 2, "Dave", "PR #142 is ready for review", DateTime.UtcNow.AddHours(-1), null, []),
            new(8, 2, "Alice", "I'll take a look after lunch", DateTime.UtcNow.AddMinutes(-50), 7, [new("👍", ["Dave"])]),
            new(9, 3, "Carol", "New mockups are in Figma — check the Design System page", DateTime.UtcNow.AddHours(-4), null, [new("❤️", ["Alice", "Bob", "Dave"])]),
        ];
    }

    public Task<List<Channel>> GetChannelsAsync()
        => Task.FromResult(_channels.ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var result = _messages
            .Where(m => m.ChannelId == channelId)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(result);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(Interlocked.Increment(ref _nextId), channelId, "You", content, DateTime.UtcNow, replyToId, []);
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (root is null) return Task.FromResult(new List<Message>());

        var thread = new List<Message> { root };
        thread.AddRange(_messages.Where(m => m.ReplyToId == rootMessageId).OrderBy(m => m.SentAt));
        return Task.FromResult(thread);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var idx = _messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return Task.CompletedTask;

        var msg = _messages[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);
        if (existing >= 0)
        {
            var r = reactions[existing];
            if (!r.Users.Contains("You"))
                reactions[existing] = r with { Users = [..r.Users, "You"] };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }
        _messages[idx] = msg with { Reactions = reactions };
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }
}

